@app.route('/token', methods=['POST'])      
def get_access_token(): 
    global auth_codes, retries  
            
    code = request.json["authorizationCode"]       
          
    if not (code in auth_codes):     # Check the authorisation token is valid or expired     
         return jsonify({"error": "Invalid/Expired Authorization Code."}), 403  
            
